#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n\"\"\"\nText to Video Generator - GUI Application\nGiao diện đơn giản, không cần Terminal\n\"\"\"\n\nimport tkinter as tk\nfrom tkinter import ttk, scrolledtext, filedialog, messagebox\nimport threading\nimport os\nfrom datetime import datetime\nfrom utils.video_creator import VideoCreator\n\nclass VideoGeneratorGUI:\n    def __init__(self, root):\n        self.root = root\n        self.root.title(\"🎬 Text to Video Generator\")\n        self.root.geometry(\"900x700\")\n        self.root.resizable(False, False)\n        \n        # Set style\n        self.root.configure(bg=\"#f0f0f0\")\n        \n        self.creator = VideoCreator()\n        self.is_processing = False\n        \n        self.setup_ui()\n    \n    def setup_ui(self):\n        \"\"\"Setup UI components\"\"\"\n        \n        # Header\n        header_frame = tk.Frame(self.root, bg=\"#2c3e50\", height=60)\n        header_frame.pack(fill=tk.X)\n        \n        title_label = tk.Label(\n            header_frame,\n            text=\"🎬 Text to Video Generator\",\n            font=(\"Arial\", 18, \"bold\"),\n            bg=\"#2c3e50\",\n            fg=\"white\"\n        )\n        title_label.pack(pady=10)\n        \n        # Main content\n        main_frame = tk.Frame(self.root, bg=\"#f0f0f0\")\n        main_frame.pack(fill=tk.BOTH, expand=True, padx=20, pady=20)\n        \n        # Text input section\n        text_label = tk.Label(\n            main_frame,\n            text=\"📝 Nhập văn bản (Text Input):\",\n            font=(\"Arial\", 12, \"bold\"),\n            bg=\"#f0f0f0\"\n        )\n        text_label.pack(anchor=tk.W, pady=(0, 5))\n        \n        # Text input area\n        self.text_input = scrolledtext.ScrolledText(\n            main_frame,\n            height=12,\n            width=100,\n            font=(\"Arial\", 11),\n            wrap=tk.WORD,\n            bg=\"white\",\n            borderwidth=2,\n            relief=tk.SOLID\n        )\n        self.text_input.pack(fill=tk.BOTH, expand=True, pady=(0, 15))\n        \n        # Sample text button\n        sample_btn = tk.Button(\n            main_frame,\n            text=\"📌 Load Sample Text\",\n            command=self.load_sample_text,\n            bg=\"#3498db\",\n            fg=\"white\",\n            font=(\"Arial\", 10),\n            padx=10,\n            pady=5,\n            cursor=\"hand2\"\n        )\n        sample_btn.pack(anchor=tk.W, pady=(0, 10))\n        \n        # Options frame\n        options_frame = tk.LabelFrame(\n            main_frame,\n            text=\"⚙️ Options\",\n            font=(\"Arial\", 11, \"bold\"),\n            bg=\"#f0f0f0\",\n            padx=10,\n            pady=10\n        )\n        options_frame.pack(fill=tk.X, pady=(0, 15))\n        \n        # Language selection\n        lang_frame = tk.Frame(options_frame, bg=\"#f0f0f0\")\n        lang_frame.pack(fill=tk.X, pady=5)\n        \n        lang_label = tk.Label(\n            lang_frame,\n            text=\"🌐 Ngôn ngữ (Language):\",\n            font=(\"Arial\", 10),\n            bg=\"#f0f0f0\"\n        )\n        lang_label.pack(side=tk.LEFT)\n        \n        self.language_var = tk.StringVar(value=\"vi\")\n        languages = [(\"🇻🇳 Tiếng Việt\", \"vi\"), (\"🇬🇧 English\", \"en\"), (\"🇫🇷 Français\", \"fr\")]\n        \n        for text, value in languages:\n            rb = tk.Radiobutton(\n                lang_frame,\n                text=text,\n                variable=self.language_var,\n                value=value,\n                bg=\"#f0f0f0\",\n                font=(\"Arial\", 10)\n            )\n            rb.pack(side=tk.LEFT, padx=10)\n        \n        # Resolution\n        res_frame = tk.Frame(options_frame, bg=\"#f0f0f0\")\n        res_frame.pack(fill=tk.X, pady=5)\n        \n        res_label = tk.Label(\n            res_frame,\n            text=\"📺 Resolution:\",\n            font=(\"Arial\", 10),\n            bg=\"#f0f0f0\"\n        )\n        res_label.pack(side=tk.LEFT)\n        \n        self.resolution_var = tk.StringVar(value=\"720p\")\n        resolutions = [(\"720p (Fast)\", \"720p\"), (\"1080p (Better)\", \"1080p\")]\n        \n        for text, value in resolutions:\n            rb = tk.Radiobutton(\n                res_frame,\n                text=text,\n                variable=self.resolution_var,\n                value=value,\n                bg=\"#f0f0f0\",\n                font=(\"Arial\", 10)\n            )\n            rb.pack(side=tk.LEFT, padx=10)\n        \n        # Buttons frame\n        buttons_frame = tk.Frame(main_frame, bg=\"#f0f0f0\")\n        buttons_frame.pack(fill=tk.X, pady=(0, 10))\n        \n        # Create video button\n        create_btn = tk.Button(\n            buttons_frame,\n            text=\"🎬 CREATE VIDEO\",\n            command=self.create_video,\n            bg=\"#27ae60\",\n            fg=\"white\",\n            font=(\"Arial\", 12, \"bold\"),\n            padx=20,\n            pady=10,\n            cursor=\"hand2\",\n            relief=tk.RAISED,\n            bd=2\n        )\n        create_btn.pack(side=tk.LEFT, padx=5)\n        \n        # Open folder button\n        folder_btn = tk.Button(\n            buttons_frame,\n            text=\"📁 Open Output Folder\",\n            command=self.open_output_folder,\n            bg=\"#e67e22\",\n            fg=\"white\",\n            font=(\"Arial\", 11),\n            padx=15,\n            pady=10,\n            cursor=\"hand2\"\n        )\n        folder_btn.pack(side=tk.LEFT, padx=5)\n        \n        # Status bar\n        self.status_var = tk.StringVar(value=\"Ready ✓\")\n        status_bar = tk.Label(\n            main_frame,\n            textvariable=self.status_var,\n            font=(\"Arial\", 10),\n            bg=\"#ecf0f1\",\n            fg=\"#2c3e50\",\n            padx=10,\n            pady=8,\n            relief=tk.SUNKEN,\n            anchor=tk.W\n        )\n        status_bar.pack(fill=tk.X)\n        \n        # Progress bar\n        self.progress = ttk.Progressbar(\n            main_frame,\n            mode='indeterminate',\n            length=400\n        )\n        self.progress.pack(fill=tk.X, pady=(10, 0))\n    \n    def load_sample_text(self):\n        \"\"\"Load sample Vietnamese text\"\"\"\n        sample = \"\"\"Xin chào, đây là video được tạo tự động từ văn bản.\nVideo này có âm thanh, hình ảnh và phụ đề rất hoàn chỉnh.\nBạn có thể thay đổi nội dung văn bản để tạo video khác.\nCông nghệ này rất hữu ích để tạo nội dung cho YouTube.\nHãy thử sử dụng và tạo ra những video tuyệt vời!\n\nBạn cũng có thể dùng để tạo video hướng dẫn học tập.\nVới công cụ này, bạn có thể tự động hóa quá trình tạo video.\nChỉ cần nhập text, công cụ sẽ tạo video hoàn chỉnh cho bạn.\"\"\"\n        \n        self.text_input.delete(\"1.0\", tk.END)\n        self.text_input.insert(\"1.0\", sample)\n        self.update_status(\"Sample text loaded ✓\")\n    \n    def create_video(self):\n        \"\"\"Create video from text\"\"\"\n        text = self.text_input.get(\"1.0\", tk.END).strip()\n        \n        if not text:\n            messagebox.showwarning(\"Warning\", \"Please enter some text first! 📝\")\n            return\n        \n        if len(text) < 10:\n            messagebox.showwarning(\"Warning\", \"Text is too short! Please enter at least 10 characters. 📝\")\n            return\n        \n        # Start processing in a separate thread\n        self.is_processing = True\n        thread = threading.Thread(target=self._process_video, args=(text,))\n        thread.start()\n    \n    def _process_video(self, text):\n        \"\"\"Process video creation in background thread\"\"\"\n        try:\n            self.update_status(\"⏳ Processing... This may take a few minutes...\")\n            self.progress.start()\n            self.root.after(0, self._disable_controls)\n            \n            # Create output directory\n            os.makedirs('output', exist_ok=True)\n            \n            # Generate timestamp for unique filename\n            timestamp = datetime.now().strftime(\"%Y%m%d_%H%M%S\")\n            output_file = f'output/video_{timestamp}.mp4'\n            \n            # Create video\n            self.creator.create_video_from_text(text, output_path=output_file)\n            \n            self.root.after(0, lambda: self._on_video_complete(output_file))\n            \n        except Exception as e:\n            self.root.after(0, lambda: self._on_video_error(str(e)))\n        finally:\n            self.progress.stop()\n            self.root.after(0, self._enable_controls)\n            self.is_processing = False\n    \n    def _on_video_complete(self, output_file):\n        \"\"\"Handle video creation completion\"\"\"\n        self.update_status(f\"✅ Video created successfully! Saved at: {output_file}\")\n        messagebox.showinfo(\n            \"Success! 🎉\",\n            f\"Video created successfully!\\n\\nFile: {output_file}\\n\\nClick 'Open Output Folder' to view it.\"\n        )\n    \n    def _on_video_error(self, error):\n        \"\"\"Handle video creation error\"\"\"\n        self.update_status(\"❌ Error creating video\")\n        messagebox.showerror(\n            \"Error ❌\",\n            f\"Error creating video:\\n\\n{error}\\n\\nMake sure FFmpeg is installed!\"\n        )\n    \n    def _disable_controls(self):\n        \"\"\"Disable controls during processing\"\"\"\n        self.text_input.config(state=tk.DISABLED)\n    \n    def _enable_controls(self):\n        \"\"\"Enable controls after processing\"\"\"\n        self.text_input.config(state=tk.NORMAL)\n    \n    def update_status(self, message):\n        \"\"\"Update status message\"\"\"\n        self.status_var.set(message)\n        self.root.update()\n    \n    def open_output_folder(self):\n        \"\"\"Open output folder\"\"\"\n        output_dir = os.path.abspath('output')\n        os.makedirs(output_dir, exist_ok=True)\n        \n        import platform\n        import subprocess\n        \n        try:\n            if platform.system() == 'Windows':\n                os.startfile(output_dir)\n            elif platform.system() == 'Darwin':  # macOS\n                subprocess.Popen(['open', output_dir])\n            else:  # Linux\n                subprocess.Popen(['xdg-open', output_dir])\n            \n            self.update_status(f\"📁 Opening folder: {output_dir}\")\n        except Exception as e:\n            messagebox.showerror(\"Error\", f\"Could not open folder: {e}\")\n\ndef main():\n    root = tk.Tk()\n    app = VideoGeneratorGUI(root)\n    root.mainloop()\n\nif __name__ == \"__main__\":\n    main()\n